    @Test
    public void testNearbyRepeatedBodyNoteIsNotAbsorbedIntoFooter() {
        StaticContainers.setIsDataLoader(true);
        StaticContainers.setIsIgnoreCharactersWithoutUnicode(false);
        StaticResources.setDocument(null);
        StaticLayoutContainers.setCurrentContentId(0);
        List<List<IObject>> contents = new ArrayList<>();
        contents.add(createPage(0, null, "18 CERAGEM BALANCE USER MANUAL"));
        contents.add(createPage(1, "※ 출수 중 출수 버튼을 터치하면 출수가 정지됩니다.",
            "19 CERAGEM BALANCE USER MANUAL"));
        contents.add(createPage(2, "※ 출수 중 출수 버튼을 터치하면 출수가 정지됩니다.",
            "20 CERAGEM BALANCE USER MANUAL"));
        contents.add(createPage(3, null, "21 CERAGEM BALANCE USER MANUAL"));

        HeaderFooterProcessor.processHeadersAndFooters(contents, true);

        Assertions.assertTrue(contents.get(1).get(1) instanceof TextLine);
        Assertions.assertEquals("※ 출수 중 출수 버튼을 터치하면 출수가 정지됩니다.",
            ((TextLine) contents.get(1).get(1)).getValue());
        Assertions.assertTrue(contents.get(2).get(1) instanceof TextLine);
        Assertions.assertEquals("※ 출수 중 출수 버튼을 터치하면 출수가 정지됩니다.",
            ((TextLine) contents.get(2).get(1)).getValue());
        Assertions.assertEquals(1,
            ((SemanticHeaderOrFooter) contents.get(1).get(contents.get(1).size() - 1)).getContents().size());
        Assertions.assertEquals(1,
            ((SemanticHeaderOrFooter) contents.get(2).get(contents.get(2).size() - 1)).getContents().size());
    }

    private static List<IObject> createPage(int pageNumber, String note, String footer) {
        List<IObject> pageContents = new ArrayList<>();
        pageContents.add(new TextLine(new TextChunk(new BoundingBox(pageNumber, 10.0, 300.0, 200.0, 310.0),
            "Body text", 10, 300.0)));
        if (note != null) {
            pageContents.add(new TextLine(new TextChunk(new BoundingBox(pageNumber, 10.0, 116.0, 260.0, 126.0),
                note, 10, 116.0)));
        }
        pageContents.add(new TextLine(new TextChunk(new BoundingBox(pageNumber, 10.0, 43.0, 200.0, 52.2),
            footer, 10, 43.0)));
        return pageContents;
    }
}

