        Assertions.assertEquals("※ 출수 중 출수 버튼을 터치하면 출수가 정지됩니다.",
            ((TextLine) contents.get(2).get(0)).getValue());
        Assertions.assertEquals(1,
            ((SemanticHeaderOrFooter) contents.get(1).get(contents.get(1).size() - 1)).getContents().size());
        Assertions.assertEquals(1,
            ((SemanticHeaderOrFooter) contents.get(2).get(contents.get(2).size() - 1)).getContents().size());
    }

    private static List<IObject> createPage(int pageNumber, String note, String footer) {
        List<IObject> pageContents = new ArrayList<>();
        pageContents.add(new TextLine(new TextChunk(new BoundingBox(pageNumber, 10.0, 300.0, 200.0, 310.0),
            "Body text", 10, 300.0)));
        if (note != null) {
            pageContents.add(new TextLine(new TextChunk(new BoundingBox(pageNumber, 10.0, 116.0, 260.0, 126.0),
                note, 10, 116.0)));
        }
        pageContents.add(new TextLine(new TextChunk(new BoundingBox(pageNumber, 10.0, 43.0, 200.0, 52.2),
            footer, 10, 43.0)));
        return pageContents;
    }
}

