                pageContentIndexes.add(-1);
                continue;
            }
            List<IObject> pageContents = sortedContents.get(pageNumber);
            int index = isHeaderDetection ? currentIndex : pageContents.size() - 1 - currentIndex;
            if (index >= 0 && index < pageContents.size()) {
                contents.add(pageContents.get(index));
                pageContentIndexes.add(index);
            } else {
                contents.add(null);
                pageContentIndexes.add(-1);
            }
        }
        Set<Integer> newIndexes = getIndexesOfHeaderOrFootersContents(contents);
        if (newIndexes.isEmpty()) {
            break;
        }
        if (currentIndex > 0) {
            Set<Integer> filteredIndexes = filterIndexesByHeaderOrFooterStackGap(newIndexes, sortedContents,
                    pageContentIndexes, isHeaderDetection);
            for (Integer newIndex : newIndexes) {
                if (!filteredIndexes.contains(newIndex)) {
                    disabledPages.set(newIndex, true);
                }
            }
            newIndexes = filteredIndexes;
        }
        for (Integer newIndex : newIndexes) {
            numberOfHeaderOrFooterContentsForEachPage.set(newIndex,
                    numberOfHeaderOrFooterContentsForEachPage.get(newIndex) + 1);
        }
        currentIndex++;
    }
    return numberOfHeaderOrFooterContentsForEachPage;
}

private static Set<Integer> filterIndexesByHeaderOrFooterStackGap(Set<Integer> newIndexes, List<List<IObject>> sortedContents,
                                                                  List<Integer> pageContentIndexes,
                                                                  boolean isHeaderDetection) {
    Set<Integer> result = new HashSet<>(newIndexes.size());
    for (Integer pageNumber : newIndexes) {
        int currentContentIndex = pageContentIndexes.get(pageNumber);
        int previousIndex = isHeaderDetection ? currentContentIndex - 1 : currentContentIndex + 1;
        List<IObject> pageContents = sortedContents.get(pageNumber);
        if (previousIndex >= 0 && previousIndex < pageContents.size() && currentContentIndex >= 0 &&
                currentContentIndex < pageContents.size() &&
                areStackedHeaderOrFooterContents(pageContents.get(previousIndex), pageContents.get(currentContentIndex),
                        isHeaderDetection)) {
            result.add(pageNumber);
        }
    }
    return result;
}

