16	package org.opendataloader.pdf.containers;
17	
18	import org.opendataloader.pdf.api.Config;
19	import org.verapdf.wcag.algorithms.entities.SemanticHeading;
20	import org.verapdf.wcag.algorithms.semanticalgorithms.consumers.ContrastRatioConsumer;
21	
22	import java.awt.*;
23	import java.io.File;
24	import java.util.Collections;
25	import java.util.LinkedList;
26	import java.util.List;
27	import java.util.Map;
28	import java.util.concurrent.ConcurrentHashMap;
29	import java.util.logging.Level;
30	import java.util.logging.Logger;
31	
32	public class StaticLayoutContainers {
33	    protected static final Logger LOGGER = Logger.getLogger(StaticLayoutContainers.class.getCanonicalName());
34	
35	    private static final ThreadLocal<Long> currentContentId = new ThreadLocal<>();
36	    private static final ThreadLocal<List<SemanticHeading>> headings = new ThreadLocal<>();
37	    private static final ThreadLocal<Integer> imageIndex = new ThreadLocal<>();
38	    private static final ThreadLocal<Boolean> isUseStructTree = new ThreadLocal<>();
39	    private static final ThreadLocal<ContrastRatioConsumer>  contrastRatioConsumer = new ThreadLocal<>();
40	    private static final ThreadLocal<Boolean> isContrastRatioConsumerFailedToCreate =  new ThreadLocal<>();
41	    private static final ThreadLocal<String> imagesDirectory = new ThreadLocal<>();
42	    private static final ThreadLocal<Boolean> embedImages = new ThreadLocal<>();
43	    private static final ThreadLocal<String> imageFormat = new ThreadLocal<>();
44	    private static final ThreadLocal<Map<Integer, Double>> replacementCharRatios = ThreadLocal.withInitial(ConcurrentHashMap::new);
45	
46	    public static void clearContainers() {
47	        currentContentId.set(1L);
48	        headings.set(Collections.synchronizedList(new LinkedList<>()));
49	        imageIndex.set(1);
50	        isUseStructTree.set(false);
51	        contrastRatioConsumer.remove();
52	        isContrastRatioConsumerFailedToCreate.set(false);
53	        imagesDirectory.set("");
54	        embedImages.set(false);
55	        imageFormat.set(Config.IMAGE_FORMAT_PNG);
56	        replacementCharRatios.get().clear();
57	    }
58	
59	    public static long getCurrentContentId() {
60	        return currentContentId.get();
61	    }
62	
63	    public static long incrementContentId() {
64	        long id = getCurrentContentId();
65	        StaticLayoutContainers.setCurrentContentId(id + 1);
66	        return id;
67	    }
68	
69	    public static void setCurrentContentId(long currentContentId) {
70	        StaticLayoutContainers.currentContentId.set(currentContentId);
71	    }
72	
73	    public static String getImagesDirectory() {
74	        return imagesDirectory.get();
75	    }
76	
77	    public static String getImagesDirectoryName() {
78	        String dir = imagesDirectory.get();
79	        return dir != null && !dir.isEmpty() ? new File(dir).getName() : "";
80	    }
81	
82	    public static void setImagesDirectory(String imagesDirectory) {
83	        StaticLayoutContainers.imagesDirectory.set(imagesDirectory);
84	    }
85	
86	    public static ContrastRatioConsumer getContrastRatioConsumer(String sourcePdfPath, String password, boolean enableAntialias, Float imagePixelSize) {
87	        try {
88	            if (contrastRatioConsumer.get() == null && !Boolean.TRUE.equals(isContrastRatioConsumerFailedToCreate.get())) {
89	                contrastRatioConsumer.set(new ContrastRatioConsumer(sourcePdfPath, password, enableAntialias, imagePixelSize));
90	            }
91	        } catch (Exception e) {
92	            LOGGER.log(Level.WARNING, "Error setting contrast ratio consumer: " + e.getMessage());
93	            isContrastRatioConsumerFailedToCreate.set(true);
94	        }
95	        return contrastRatioConsumer.get();
96	    }
97	
98	    public static void closeContrastRatioConsumer() {
99	        try {
100	            if (contrastRatioConsumer.get() != null) {
101	                contrastRatioConsumer.get().close();
102	                contrastRatioConsumer.remove();
103	            }
104	        } catch (Exception e) {
105	            LOGGER.log(Level.WARNING, "Error closing contrast ratio consumer: " + e.getMessage());
106	        }
107	    }
108	
109	    public static List<SemanticHeading> getHeadings() {
110	        return headings.get();
